                     <input 
                        type="text" 
                        id="name"
                        aria-labelledby="label-name"
                        aria-invalid={!!errors.name}
                        className={getInputClass('name')}
                        placeholder={focusedField === 'name' ? '' : 'Full Name'}
                        value={formData.name}
