    const typeCode = () => {
      if (charIndex <= CODE_SNIPPET.length) {
        setTypedCode(CODE_SNIPPET.slice(0, charIndex));
        const char = CODE_SNIPPET[charIndex - 1];
        let delay = 35; // Base speed refined

        // Logical pauses for "thinking" or "completing" a line
        if (char === '\n') delay = 600;
        else if (char === ';') delay = 300;
        else if (char === '{' || char === '}') delay = 450;
        else if (char === '.') delay = 200;

        charIndex++;
        timeoutId = setTimeout(typeCode, delay);
      } else {
        setIsCodeDone(true);
      }
    };

