export const Portfolio: React.FC<PortfolioProps> = ({ limit }) => {
  const [selectedCategories, setSelectedCategories] = useState<string[]>(() => {
    try {
      return JSON.parse(localStorage.getItem(STORAGE_KEY_CATEGORIES) || '[]');
    } catch {
      return [];
    }
  });

  const [selectedTags, setSelectedTags] = useState<string[]>(() => {
    try {
      return JSON.parse(localStorage.getItem(STORAGE_KEY_TAGS) || '[]');
    } catch {
      return [];
    }
  });

  const [loading, setLoading] = useState(true);
  const [modalState, setModalState] = useState<{ project: Project; autoPlay: boolean } | null>(null);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_CATEGORIES, JSON.stringify(selectedCategories));
    localStorage.setItem(STORAGE_KEY_TAGS, JSON.stringify(selectedTags));
  }, [selectedCategories, selectedTags]);

  useEffect(() => { 
    const timer = setTimeout(() => setLoading(false), 800); 
    return () => clearTimeout(timer);
  }, []);

  const categories = useMemo(() => [ALL_CATEGORY, ...Array.from(new Set(PROJECTS.map(p => p.category)))], []);
  const allTags = useMemo(() => Array.from(new Set(PROJECTS.flatMap(p => p.technologies || []))).sort(), []);

  // Faceted counts logic: how many projects match CURRENT filters if this tag was chosen?
  const dynamicCategoryCounts = useMemo(() => {
    const counts: Record<string, number> = {};
    PROJECTS.forEach(p => {
      const matchTags = selectedTags.length === 0 || (p.technologies && selectedTags.some(tag => p.technologies?.includes(tag)));
      if (matchTags) {
        counts[p.category] = (counts[p.category] || 0) + 1;
      }
    });
    return counts;
  }, [selectedTags]);

  const dynamicTagCounts = useMemo(() => {
    const counts: Record<string, number> = {};
    PROJECTS.forEach(p => {
      const matchCat = selectedCategories.length === 0 || selectedCategories.includes(p.category);
      if (matchCat) {
        p.technologies?.forEach(t => {
          counts[t] = (counts[t] || 0) + 1;
        });
      }
    });
    return counts;
  }, [selectedCategories]);

  const filteredProjects = useMemo(() => {
    let projs = PROJECTS.filter(p => {
      const matchCat = selectedCategories.length === 0 || selectedCategories.includes(p.category);
      const matchTags = selectedTags.length === 0 || (p.technologies && selectedTags.some(tag => p.technologies?.includes(tag)));
      return matchCat && matchTags;
    });
    return limit ? projs.slice(0, limit) : projs;
  }, [selectedCategories, selectedTags, limit]);

  const toggleCategory = (cat: string) => {
    if (cat === ALL_CATEGORY) setSelectedCategories([]);
    else setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat]);
  };

  const toggleTag = (tag: string) => setSelectedTags(prev => prev.includes(tag) ? prev.filter(t => t !== tag) : [...prev, tag]);

  const shareProject = (platform: 'linkedin' | 'twitter') => {
    if (!modalState) return;
    const url = window.location.href;
    const text = `Check out this amazing project by OITS Dhaka: ${modalState.project.title}`;
    const links = {
      linkedin: `https://www.linkedin.com/sharing/share-offsite/?url=${encodeURIComponent(url)}`,
      twitter: `https://twitter.com/intent/tweet?text=${encodeURIComponent(text)}&url=${encodeURIComponent(url)}`
    };
    window.open(links[platform], '_blank');
  };

  return (
    <section id="portfolio" className="py-24 bg-slate-50 dark:bg-slate-950 min-h-screen transition-colors duration-300">
      <div className="container mx-auto px-6">
        <div className="mb-16 flex flex-col lg:flex-row gap-12">
           {!limit && (
             <aside className="w-full lg:w-80 space-y-8">
                <h4 className="text-xs font-black text-slate-400 uppercase tracking-[0.3em] mb-6">Verticals</h4>
                <nav className="flex lg:flex-col gap-3 overflow-x-auto no-scrollbar pb-2" role="group" aria-label="Vertical Filter">
                  {categories.map(cat => {
                    const active = cat === ALL_CATEGORY ? selectedCategories.length === 0 : selectedCategories.includes(cat);
                    const count = cat === ALL_CATEGORY ? PROJECTS.length : (dynamicCategoryCounts[cat] || 0);
                    return (
                      <button 
                        key={cat} 
                        onClick={() => toggleCategory(cat)} 
                        aria-pressed={active} 
                        className={`flex items-center justify-between px-5 py-3 rounded-2xl text-sm font-bold text-left whitespace-nowrap transition-all border outline-none focus-visible:ring-4 focus-visible:ring-blue-500/20 active:scale-[0.97] ${active ? 'bg-slate-900 dark:bg-blue-600 text-white shadow-xl border-transparent translate-x-1' : 'bg-white dark:bg-slate-900 text-slate-600 border-slate-200 dark:border-slate-800 hover:border-blue-300'}`}
                      >
                        <span className="flex items-center gap-2">
                           {cat}
                           {active && cat !== ALL_CATEGORY && <Check size={14} />}
                        </span>
                        <span className={`text-[10px] px-2 py-0.5 rounded-md font-black ${active ? 'bg-white/20 text-white' : 'bg-slate-100 dark:bg-slate-800 text-slate-400'}`}>
                           {count}
                        </span>
                      </button>
                    );
                  })}
                </nav>
             </aside>
           )}
           <div className="flex-1">
              {!limit && (
                <div className="bg-white dark:bg-slate-900 p-10 rounded-3xl border border-slate-200 dark:border-slate-800 mb-12 shadow-sm relative overflow-hidden group/filter">
                  <div className="flex items-center justify-between mb-8">
                    <div className="flex items-center gap-3">
                      <div className="p-2.5 bg-blue-100 dark:bg-blue-900/30 rounded-xl text-blue-600 dark:text-blue-400">
                        <Tag size={20}/>
                      </div>
                      <span className="font-black text-xl tracking-tight text-slate-900 dark:text-white">Technology Filters</span>
                    </div>
                    {(selectedTags.length > 0 || selectedCategories.length > 0) && (
                      <button 
                        onClick={() => { setSelectedCategories([]); setSelectedTags([]); }} 
                        className="text-xs text-blue-600 dark:text-blue-400 flex items-center gap-2 font-black uppercase tracking-widest hover:underline px-4 py-2 bg-blue-50 dark:bg-blue-900/20 rounded-full"
                      >
                        <RotateCcw size={14}/> Reset Filters
                      </button>
                    )}
                  </div>
                  <div className="flex flex-wrap gap-3" role="group" aria-label="Tech Stack Filter">
                    {allTags.map(tag => {
                      const active = selectedTags.includes(tag);
                      const count = dynamicTagCounts[tag] || 0;
                      return (
                        <button 
                          key={tag} 
                          onClick={() => toggleTag(tag)} 
                          aria-pressed={active} 
                          className={`flex items-center gap-2 px-5 py-2 rounded-full text-xs font-black border transition-all active:scale-90 outline-none focus-visible:ring-4 focus-visible:ring-blue-500/20 ${active ? 'bg-blue-600 border-blue-600 text-white shadow-lg shadow-blue-500/30 scale-105' : 'bg-slate-50 dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-500 hover:border-blue-400'}`}
                        >
                          {tag}
                          <span className={`text-[9px] px-1.5 py-0.5 rounded-full ${active ? 'bg-white/20 text-white' : 'bg-slate-200 dark:bg-slate-700 text-slate-400'}`}>
                             {count}
                          </span>
                        </button>
                      );
                    })}
                  </div>
                </div>
              )}
              {/* Added a key to the grid container based on filter selections to help React animate the entire view on filter change */}
              <div 
                key={selectedCategories.join('-') + selectedTags.join('-')}
                className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-10 min-h-[500px] animate-in fade-in slide-in-from-bottom-4 duration-700"
              >
                {loading ? [1,2,3].map(i => <ProjectSkeleton key={i}/>) : filteredProjects.map((p, i) => (
                  <ProjectCard 
                    key={p.id} 
                    project={p} 
                    index={i} 
                    highlightedTags={selectedTags} 
                    onClick={() => setModalState({ project: p, autoPlay: false })} 
                    onViewDemo={() => setModalState({ project: p, autoPlay: true })} 
                  />
                ))}
                {!loading && filteredProjects.length === 0 && (
                   <div className="col-span-full py-32 text-center bg-white dark:bg-slate-900 rounded-[3rem] border border-dashed border-slate-200 dark:border-slate-800 animate-in zoom-in-95 duration-500">
                      <div className="w-20 h-20 bg-slate-50 dark:bg-slate-800/50 rounded-full flex items-center justify-center mx-auto mb-6">
                        <X className="text-slate-300" size={32} />
                      </div>
                      <p className="text-xl font-bold text-slate-400">No projects match the selected filters.</p>
                      <button onClick={() => {setSelectedCategories([]); setSelectedTags([]);}} className="mt-4 text-blue-600 font-black uppercase text-xs tracking-widest hover:underline">Clear all filters</button>
                   </div>
                )}
              </div>
           </div>
        </div>
      </div>
      {modalState && (
        <div className="fixed inset-0 z-[101] flex items-center justify-center p-4 sm:p-8">
          <div className="absolute inset-0 bg-slate-900/95 backdrop-blur-md animate-in fade-in duration-500" onClick={() => setModalState(null)}/>
          <div className="relative w-full max-w-6xl bg-white dark:bg-slate-900 rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-500 max-h-[90vh] flex flex-col pointer-events-auto">
            <div className="relative aspect-video bg-black flex-shrink-0">
              {modalState.autoPlay && modalState.project.demoVideoUrl ? (
                <CustomVideoPlayer 
                  src={modalState.project.demoVideoUrl} 
                  captionsUrl={modalState.project.captionsUrl} 
                  poster={modalState.project.imageUrl} 
                  onClose={() => setModalState({ ...modalState, autoPlay: false })} 
                />
              ) : (
                <div className="relative w-full h-full group/modal-img">
                  <img 
                    src={modalState.project.imageUrl || FALLBACK_IMAGE} 
                    alt={modalState.project.title} 
                    className="w-full h-full object-cover"
                    onError={(e) => {
                      (e.target as HTMLImageElement).src = FALLBACK_IMAGE;
                    }}
                  />
                  <button 
                    onClick={() => setModalState(null)} 
                    className="absolute top-6 right-6 p-3 bg-black/50 backdrop-blur-md rounded-full text-white hover:bg-black/70 transition-all active:scale-90 z-20"
                    aria-label="Close Case Study"
                  >
                    <X size={24}/>
                  </button>
                  <div className="absolute inset-0 bg-gradient-to-t from-black/90 via-black/20 to-transparent flex flex-col justify-end p-10 md:p-16">
                    <h3 className="text-4xl md:text-6xl font-black text-white mb-4 tracking-tighter">{modalState.project.title}</h3>
                    <div className="flex gap-4">
                      {modalState.project.demoVideoUrl && (
                        <Button 
                          onClick={() => setModalState({ ...modalState, autoPlay: true })} 
                          variant="primary" 
                          className="rounded-full shadow-2xl shadow-blue-500/40"
                        >
                          <Play size={18} className="mr-2" /> Play Showreel
                        </Button>
                      )}
                    </div>
                  </div>
                </div>
              )}
            </div>
            <div className="p-10 md:p-16 overflow-y-auto">
              <div className="max-w-4xl">
                 <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-10">
                    <h4 className="text-sm font-black text-blue-600 dark:text-blue-400 uppercase tracking-[0.3em] flex items-center gap-2">
                      <Info size={16} /> Detailed Case Study
                    </h4>
                    <div className="flex items-center gap-4">
                      <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Share Project:</span>
                      <button onClick={() => shareProject('linkedin')} className="p-2 bg-slate-100 dark:bg-slate-800 rounded-full hover:bg-blue-600 hover:text-white transition-all shadow-sm">
                        <Linkedin size={18} />
                      </button>
                      <button onClick={() => shareProject('twitter')} className="p-2 bg-slate-100 dark:bg-slate-800 rounded-full hover:bg-blue-400 hover:text-white transition-all shadow-sm">
                        <Twitter size={18} />
                      </button>
                    </div>
                 </div>

                 <p className="text-slate-700 dark:text-slate-300 text-xl leading-relaxed mb-10 font-medium">
                   {modalState.project.fullDescription || modalState.project.description}
                 </p>
                 <div className="flex flex-wrap gap-3">
                    {modalState.project.technologies?.map(tech => (
                      <span key={tech} className="px-5 py-2 bg-slate-50 dark:bg-slate-800 rounded-xl text-sm font-bold text-slate-700 dark:text-slate-200 border border-slate-100 dark:border-slate-700">
                        {tech}
                      </span>
                    ))}
                 </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </section>
  );
};

import React, { useEffect, useRef, useState } from 'react';
import { Link } from 'react-router-dom';
import { ArrowRight, Terminal as TerminalIcon, Zap, PlayCircle, MessageCircle } from 'lucide-react';
import { Button } from './ui/Button';
import { TAGLINE } from '../constants';

const TITLE_TEXT = "Building the Digital Elite";
const CODE_SNIPPET = `// OITS Dhaka Project Config
const project = {
  client: "Innovative Startup",
  goals: ["Scalability", "Security"],
  techStack: ["React", "Next.js", "AWS"],
  status: "Ready for Launch"
};

async function deploy() {
  console.log("Initializing Engineering...");
  await project.initialize();
  return "Excellence Delivered.";
}`;

const TRUSTED_BY = [
  { name: 'TECHFLOW', icon: 'TF', color: 'bg-blue-500/10 text-blue-600 dark:text-blue-400' },
  { name: 'CLOUDSCALE', icon: 'CS', color: 'bg-indigo-500/10 text-indigo-600 dark:text-indigo-400' },
  { name: 'INNOVATE', icon: 'IN', color: 'bg-cyan-500/10 text-cyan-600 dark:text-cyan-400' },
  { name: 'NEXUS', icon: 'NX', color: 'bg-blue-600/10 text-blue-700 dark:text-blue-500' },
  { name: 'VANTAGE', icon: 'VT', color: 'bg-sky-500/10 text-sky-600 dark:text-sky-400' },
];

export const Hero: React.FC = () => {
  const [isVisible, setIsVisible] = useState(false);
  const [typedTitle, setTypedTitle] = useState("");
  const [typedTagline, setTypedTagline] = useState("");
  const [typedCode, setTypedCode] = useState("");
  const [isTitleDone, setIsTitleDone] = useState(false);
  const [isTaglineDone, setIsTaglineDone] = useState(false);
  const [isCodeDone, setIsCodeDone] = useState(false);
  const [scrollY, setScrollY] = useState(0);
  const heroRef = useRef<HTMLElement>(null);

  // Parallax and Intersection Observer logic
  useEffect(() => {
    const handleScroll = () => {
      window.requestAnimationFrame(() => {
        setScrollY(window.scrollY);
      });
    };
    window.addEventListener('scroll', handleScroll, { passive: true });

    const observer = new IntersectionObserver(([entry]) => {
      if (entry.isIntersecting) setIsVisible(true);
    }, { threshold: 0.1 });

    if (heroRef.current) observer.observe(heroRef.current);

    return () => {
      window.removeEventListener('scroll', handleScroll);
      observer.disconnect();
    };
  }, []);

  // Sequential Typing Engine
  // 1. Title Typing (80ms/char)
  useEffect(() => {
    if (!isVisible) return;
    let titleIndex = 0;
    const typeTitle = () => {
      if (titleIndex <= TITLE_TEXT.length) {
        setTypedTitle(TITLE_TEXT.slice(0, titleIndex));
        titleIndex++;
        setTimeout(typeTitle, 80);
      } else {
        setIsTitleDone(true);
      }
    };
    const timeout = setTimeout(typeTitle, 500);
    return () => clearTimeout(timeout);
  }, [isVisible]);

  // 2. Tagline Typing (45ms/char)
  useEffect(() => {
    if (!isTitleDone) return;
    let taglineIndex = 0;
    const typeTagline = () => {
      if (taglineIndex <= TAGLINE.length) {
        setTypedTagline(TAGLINE.slice(0, taglineIndex));
        taglineIndex++;
        setTimeout(typeTagline, 45);
      } else {
        setIsTaglineDone(true);
      }
    };
    const timeout = setTimeout(typeTagline, 300);
    return () => clearTimeout(timeout);
  }, [isTitleDone]);

  // 3. Code Snippet Typing (Natural character-by-character with syntax pauses)
  useEffect(() => {
    if (!isTaglineDone) return;
    let charIndex = 0;
    let timeoutId: ReturnType<typeof setTimeout>;

    const typeCode = () => {
      if (charIndex <= CODE_SNIPPET.length) {
        setTypedCode(CODE_SNIPPET.slice(0, charIndex));
        const char = CODE_SNIPPET[charIndex - 1];
        let delay = 30; // Moderate base speed

        // Logical pauses for realistic "typing" feel
        if (char === '\n') delay = 550;      // Line completion pause
        else if (char === ';') delay = 300;   // Statement completion pause
        else if (char === '{' || char === '}') delay = 450; // Block start/end
        else if (char === ',') delay = 200;   // Property separation pause

        charIndex++;
        timeoutId = setTimeout(typeCode, delay);
      } else {
        setIsCodeDone(true);
      }
    };

    const initialDelay = setTimeout(typeCode, 700);
    return () => {
      clearTimeout(timeoutId);
      clearTimeout(initialDelay);
    };
  }, [isTaglineDone]);

  return (
    <section 
      ref={heroRef} 
      id="home" 
      className="relative pt-32 pb-24 md:pt-48 md:pb-40 lg:pt-60 lg:pb-56 overflow-hidden min-h-[95vh] lg:min-h-screen flex items-center bg-slate-950 transition-colors duration-500"
    >
      {/* Subtle Parallax Background with Tuned Dark Overlay */}
      <div className="absolute top-0 left-0 w-full h-full -z-10 overflow-hidden pointer-events-none">
        <div 
          className="absolute inset-0 bg-cover bg-center opacity-40 scale-110 will-change-transform transition-transform duration-75 ease-out"
          style={{ 
            backgroundImage: 'url("https://images.unsplash.com/photo-1555066931-4365d14bab8c?auto=format&fit=crop&q=80&w=2070")',
            transform: `translate3d(0, ${scrollY * 0.12}px, 0)` 
          }}
          aria-hidden="true"
        />
        {/* Layered dark overlay (75% opacity) for high readability while retaining background depth */}
        <div className="absolute inset-0 bg-slate-950/75 backdrop-blur-[1px]" />
        {/* Gradient mask for smooth transitions and text pop */}
        <div className="absolute inset-0 bg-gradient-to-b from-slate-950/60 via-transparent to-slate-950" />
      </div>

      <div className="container mx-auto px-6 relative z-10">
        <div className="flex flex-col lg:flex-row items-center gap-16 lg:gap-24 xl:gap-32">

          <div className="flex-1 space-y-10 md:space-y-14 text-center lg:text-left w-full">
            <div className={`inline-flex items-center gap-2 px-5 py-2 rounded-full bg-blue-500/10 border border-blue-400/20 text-[10px] md:text-xs font-black text-blue-300 uppercase tracking-[0.3em] transition-all duration-1000 transform ${isVisible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4'}`}>
              <Zap size={14} className="fill-current animate-pulse text-blue-400" />
              <span>Future-Proof Software Engineering</span>
            </div>

            {/* Title with Sequential Animation and Blinking Cursor */}
            <h1 className={`text-4xl sm:text-6xl md:text-8xl lg:text-7xl xl:text-9xl font-black text-white tracking-tighter leading-[1.0] min-h-[2.1em] md:min-h-[1.1em] transition-all duration-1000 transform ${isVisible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-8'}`}>
              Building the <br className="hidden md:block"/>
              <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-400 via-indigo-300 to-blue-200 inline-block">
                {typedTitle}
                {!isTitleDone && isVisible && (
                  <span className="inline-block w-[3px] md:w-[6px] h-[0.7em] bg-blue-500 ml-2 animate-pulse align-middle" />
                )}
              </span>
            </h1>

            <div className={`space-y-10 md:space-y-12 transition-all duration-1000 delay-300 transform ${isVisible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-10'}`}>
              {/* Tagline Animation with Cursor */}
              <p className="text-lg sm:text-xl md:text-3xl text-slate-300 max-w-2xl mx-auto lg:mx-0 leading-relaxed font-medium min-h-[3.5rem] md:min-h-0">
                {typedTagline}
                {isTitleDone && !isTaglineDone && (
                  <span className="inline-block w-[2px] h-[0.8em] bg-blue-400 ml-1 animate-pulse align-middle" />
                )}
              </p>

              {/* CTAs with Refined Styles and Hover Effects */}
              <div className="flex flex-col items-center lg:items-start gap-8">
                <div className="flex flex-col sm:flex-row items-center gap-5 sm:gap-6 justify-center lg:justify-start w-full">
                  <Link to="/contact" className="w-full sm:w-auto">
                    <Button 
                      size="lg" 
                      variant="primary" 
                      className="group relative transition-all duration-500 hover:scale-[1.05] hover:-translate-y-1.5 hover:bg-blue-500 hover:shadow-[0_20px_50px_rgba(37,99,235,0.4)] px-12 md:px-14 shadow-2xl shadow-blue-600/30 active:scale-95 w-full bg-blue-600 text-white border-none rounded-2xl overflow-hidden font-black"
                    >
                      <span className="relative z-10 flex items-center justify-center gap-2">
                        Request a Quote
                        <ArrowRight className="w-5 h-5 transition-transform group-hover:translate-x-1.5" />
                      </span>
                    </Button>
                  </Link>
                  <Link to="/portfolio" className="w-full sm:w-auto">
                    <Button 
                      variant="secondary" 
                      size="lg" 
                      className="group transition-all duration-500 hover:scale-[1.05] hover:-translate-y-1.5 bg-white/10 backdrop-blur-md text-white border border-white/20 active:scale-95 w-full rounded-2xl flex items-center justify-center gap-2 px-12 md:px-14 hover:bg-white/20 hover:shadow-[0_20px_50px_rgba(255,255,255,0.1)] shadow-xl font-black"
                    >
                      <PlayCircle size={20} className="transition-transform group-hover:scale-110" />
                      Request a Demo
                    </Button>
                  </Link>
                </div>

                <Link to="/contact" className="w-full sm:w-auto">
                  <Button 
