      const nextChar = CODE_SNIPPET[typedCode.length];

      // Determine typing speed for natural feeling
      let delay = 45; // Base typing speed

      if (nextChar === '\n') delay = 600; // Pause for thought at line breaks
      else if ([';', '{', '}'].includes(nextChar)) delay = 250; // Semantic pauses
      else if (nextChar === ' ') delay = 15; // Faster spaces

      // Add small random jitter for human-like rhythm
      delay += Math.random() * 30 - 15;

      const timeout = setTimeout(() => {
        setTypedCode(CODE_SNIPPET.slice(0, typedCode.length + 1));
      }, Math.max(5, delay));
      return () => clearTimeout(timeout);
    }
  }, [isTaglineDone, typedCode]);

